### Instruction:
Design a program in JavaScript for searching a large collection of documents for relevant results.

### Response:
const searchDocuments = (documents, query) => {   
  // Initiliaze a empty array of matches  
  const matches = [];    
  // Iterate through each document in the collection   
  documents.forEach(document => {   
  // Split the document using whitespace    
  const words = document.split(' ');    
  // Iterate through words in the document  
  words.forEach(word => {      
      // Check for a match in each word       
      if (word.toLowerCase().includes(query.toLowerCase())) {            
        // If a match is found, add to matches array         
        matches.push(document);       
      }    
  });   
  });   
  // Return the array of matches   
  return matches; 
};

### Instruction:
Develop a JavaScript function that takes a positive integer as input and prints out its binary equivalent.

### Response:
function convertToBinary(num) {
  binary = "";
  while (num > 0) {
    binary = (num % 2) + binary;
    num = Math.floor(num / 2);
  }
  return binary;
}

const result = convertToBinary(42);
console.log(result);

