### Instruction:
Create a program in C# to sort a list of randomly generated numbers from lowest to highest by implementing a Bubble Sort algorithm.

### Response:
using System;

namespace SortList
{
    class Program
    {
        public static void Main()
        {
            int[] array = new int[] { 4, 2, 1, 3 };

            int n = array.Length;
            bool swapped;

            do
            {
                swapped = false;
                for (int i = 0; i < n - 1; i++)
                {
                    if (array[i] > array[i + 1])
                    {
                        // swap elements
                        int temp = array[i];
                        array[i] = array[i + 1];
                        array[i + 1] = temp;
                        swapped = true;
                    }
                }
            }
            while (swapped == true);

            Console.WriteLine("Sorted list:");
            foreach (int num in array)
            {
                Console.Write(num + " ");
            }
            Console.WriteLine();

        }
    }
}

