Design a program in JavaScript which will return an array containing the union of two given arrays.

### Response:
function unionArrays (arr1, arr2) {
  let result = [];
  let set = new Set(arr1);

  for (let i = 0; i < arr2.length; i++) {
    if (!set.has(arr2[i])) {
      result.push(arr2[i]);
    }
  }

  return result.concat(arr1);
}

