using namespace std;

void Fib(int start, int end) 
{ 
    int first = 0; 
    int second = 1; 
    int next; 

    while (first <= end) 
    { 
        if (first >= start) 
            cout << first << " ";
        next = first + second; 
        first = second; 
        second = next; 
    }
    cout << endl;
} 

