}

### Instruction:
Write a C program to print the Armstrong numbers (numbers which are the sum of the cubes of their individual digits) between 1 and 1000.

### Response:
#include <stdio.h>
#include <math.h>

int main()
{
    int num, originalNum, lastDigit, digits, sum;

    printf("Armstrong numbers between 1 and 1000 are: \n");

    for(num = 1; num <= 1000; num++) {
        sum = 0;
        originalNum = num;


        // Digits calculation
        digits = (int) log10(num) + 1;

        while (num > 0) {
            // Extract last digit and append it to sum
            lastDigit = num % 10; 
            sum = sum + round(pow(lastDigit, digits)); 

            // Checking for Armstrong number 
            num = num / 10;
        }

        if(originalNum == sum) {
            printf("%d, ", originalNum);
        }
    }

    return 0;
}

