### Instruction:
Create an application in C++ to obtain the maximum depth of a given binary tree.

### Response:
int maxDepth(struct Node* node) 
{ 
    if (node == NULL) 
        return 0; 
    else
    { 
        /* compute the depth of each subtree */
        int lDepth = maxDepth(node->left); 
        int rDepth = maxDepth(node->right); 

        /* use the larger one */
        if (lDepth > rDepth) 
            return(lDepth + 1); 
        else return(rDepth + 1); 
    } 
}

