### Instruction:
Write a C ++ program to optimize a given matrix with specific values.

### Response:
#include <iostream>
#include <vector> 

using namespace std;

void optimizeMatrix (vector<vector<int>> &mat, int val) { 
  // Iterate over the matrix
  for (int i = 0; i < mat.size(); i++) { 
    for (int j = 0; j < mat[i].size(); j++) { 
      // Substitute all elements to be 
      // greater than or equal to value
      if (mat[i][j] < val) 
        mat[i][j] = val; 
    } 
  } 
} 

int main() 
{ 
  // Create a matrix 
  vector<vector<int>> mat = { {4, 5, 7}, 
                        {9, 1, 8}, 
                        {1, 2, 4} }; 
  int val = 3; 
  // print matrix
  optimizeMatrix(mat, val); 
  // Print after optimization
  for (int i = 0; i < mat.size(); i++) { 
    for (int j = 0; j < mat[i].size(); j++) 
      cout << mat[i][j] << " "; 
    cout << endl; 
  } 
  return 0; 
}

### Instruction:
Create a React application to input two numbers and subtract them, displaying the result.

### Response:
import React, { useState } from "react";

const App = () => {
  const [input1, setInput1] = useState(0);
  const [input2, setInput2] = useState(0);
  const [result, setResult] = useState(0);

  const handleInput1Change = (e) => {
    setInput1(e.target.value);
  };

  const handleInput2Change = (e) => {
    setInput2(e.target.value);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setResult(Number(input1) - Number(input2));
  };

  return (
    <>
      <form onSubmit={handleSubmit}>
        <input
          type="number"
          value={input1}
          onChange={handleInput1Change}
        />
        -
        <input type="number" value={input2} onChange={handleInput2Change} />
        <button type="submit">Calculate</button>
      </form>
      <p>Result: {result}</p>
    </>
  );
};

export default App;

