### Instruction:
Find the most common value in a given list.

### Response:
def most_common_value(lst):
    freq_dict = {}

    # Iterate over the list and store the frequencies in a dictionary
    for item in lst:
        if item in freq_dict:
            freq_dict[item] += 1
        else:
            freq_dict[item] = 1

    # Sort the dictionary by values and return the key of the most frequent item
    return sorted(freq_dict, key=freq_dict.get, reverse=True)[0]

