#include <string>
#include <algorithm>

using namespace std;

string longest_word(string str) {
    string longest_word;
    string current_word;

    str.push_back(' ');

    for (int i = 0; i < str.length(); i++) {
        if (isspace(str[i])) {
            if (current_word.length() > longest_word.length()) {
                longest_word = current_word;
            }
            current_word.clear();
        } else {
            current_word.push_back(str[i]);
        }
    }
    return longest_word;
}

int main() {
