#include <cmath>

using namespace std;

// Function to find the closest value to the target
float findClosest(float arr[], int n, float target)
{
    // Initialize closest value
    float closest = arr[0];

    // Start loop from 1
    for (int i = 1; i < n; i++)
    {
        // Check if current value is closer than 
        // previous value
        float diff = abs(target - arr[i]);
        if (abs(target - closest) > diff)
            closest = arr[i];
    }

    return closest;
}

