Design an algorithm to find all the elements that occur an odd number of times in an array.

### Response:
function findOddOccurrences(arr) { 
    let result = []; 

    // Iterate over each element 
    for (let i = 0; i < arr.length; i++) { 

        // Initialize count 
        let count = 0; 

        // Iterate over the rest of the elements 
        for (let j = 0; j < arr.length; j++) { 
            // If the current element is equal to other, 
            // increment the count 
            if (arr[i] == arr[j]) { 
                count++; 
            } 
        } 

        // If the count is odd, add the element to the result 
        if (count % 2 != 0) { 
            result.push(arr[i]); 
        } 
    } 

    return result; 
}

