pragma solidity ^0.6.6;

contract ToDoList {
    struct Task {
        string title;
        bool status;
    }

    // Define an array to store tasks
    Task[] tasks;

    // Create a task
    function createTask(string memory _title) public {
        Task memory newTask = Task(_title, false);
        tasks.push(newTask);
    }

    // Check off a task
    function checkOffTask(uint _id) public {
        Task storage task = tasks[_id];
        require(task.status == false, "Task already checked off");
        task.status = true;
    }

