def rot13(string):
    output = ""
    for char in string:
        if char == " ":
            output += char
            continue
        ascii_code = ord(char)
        if ascii_code >= 97 and ascii_code <= 122:
            if ascii_code <= 109:
                ascii_code += 13
            else:
                ascii_code -= 13
        else:
            if ascii_code <= 77:
                ascii_code += 13
            else:
                ascii_code -= 13
        output += chr(ascii_code)
    return output

