public static boolean checkAnagrams(String s1, String s2) { 
    int[] count1 = new int[256]; 
    int[] count2 = new int[256]; 

    // edge cases
    if (s1.length() != s2.length()) 
        return false; 

    for (int i = 0; i < s1.length(); i++) { 
        count1[s1.charAt(i)]++; 
        count2[s2.charAt(i)]++; 
    } 

    for (int i = 0; i < 256; i++) 
