import java.awt.*;
import javax.swing.JApplet;

public class SpiralApplet extends JApplet {

    public void paint(Graphics canvas) {
        int width = getWidth();
        int height = getHeight();

        int x = width/2;
        int y = height/2;
        int size = 200;
        int angle = 0;
        int thickness = 5;
        int mult = 1;

        for (int i = 0; i < 500; i++) {
            // draw a line
            canvas.drawLine(x, y, x + (int)(Math.cos(Math.toRadians(angle)) * size), 
                                y + (int)(Math.sin(Math.toRadians(angle)) * size));
