def wordFrequency(text):
    word_dict = {}
    words = text.split(" ") 
    for word in words:
        if word in word_dict:
            word_dict[word] += 1
        else:
            word_dict[word] = 1

    sorted_dict = sorted(word_dict.items(), key=lambda x: x[1], reverse = True) 
    top_three = sorted_dict[:3]
    for item in top_three:
        print(item)

